const path = "../../tpke_keystore"

type addrIdx struct {
	addr common.Address
	i    int
}

var addrsPrivnet = []addrIdx{
	{addr: common.HexToAddress("0x74f4effb0b538baec703346b03b6d9292f53a4cd"), i: 1},
	{addr: common.HexToAddress("0x910ad1641b7125eff746accdca1f11148b22f472"), i: 2},
	{addr: common.HexToAddress("0xfef5f250af14df73f983caab7b1f5002189c42e0"), i: 3},
	{addr: common.HexToAddress("0xc51964013acbc6b271feecb0febd9e7a01202930"), i: 4},
	{addr: common.HexToAddress("0xc5bbd9652546bc96be3dec97a38ee335f7873dfa"), i: 5},
	{addr: common.HexToAddress("0x26f1794b81df2b832545b8b6bbca196b82e4feb1"), i: 6},
	{addr: common.HexToAddress("0x0b51369d02e47ee3f143391b837aa08c31aaa19b"), i: 7},
}

func init() {
	slices.SortFunc(addrsPrivnet, func(a, b addrIdx) int {
		return common.Address.Cmp(a.addr, b.addr)
	})
}

func TestTPKE(t *testing.T) {
	addrsIdxPrivnet := make([]common.Address, len(addrsPrivnet))
	for i := range addrsIdxPrivnet {
		addrsIdxPrivnet[i] = addrsPrivnet[i].addr
	}

	source := rand.NewSource(time.Now().UnixNano())
	random := rand.New(source)

	pubs := make([]*ecies.PublicKey, size)
	kss := make([]*AMEVKeyStore, size)
	for i := 0; i < size; i++ {
		key, _ := ecies.GenerateKey(random, crypto.S256(), nil)
		pubs[i] = &key.PublicKey
		ks, err := NewKeyStore(addrsPrivnet[i].addr, key, size, threshold)
		if err != nil {
			t.Fatalf(err.Error())
		}
		kss[i] = ks
	}

	msgbox := make([][][]byte, size)
	pvssbox := make([][]byte, size)
	for i := 0; i < size; i++ {
		// No reshare to handle
		_, _, err := kss[i].OnValidatorList(addrsIdxPrivnet, pubs)
		if err != nil {
			t.Fatalf(err.Error())
		}
		// Handle share
		msgs, pvss, err := kss[i].OnReshareFinish()
		if err != nil {
			t.Fatalf(err.Error())
		}
		msgbox[i] = msgs
		pvssbox[i] = pvss
	}

	for i := 0; i < size; i++ {
		for j := 0; j < size; j++ {
			err := kss[i].ReceiveSecretShare(kss[j].address, msgbox[j], pvssbox[j])
			if err != nil {
				t.Fatalf(err.Error())
			}
		}
	}

	for i := 0; i < size; i++ {
		err := kss[i].OnEpochChange()
		if err != nil {
			t.Fatalf(err.Error())
		}
	}

	for i := range kss {
		ksBytes, err := kss[i].Bytes()
		require.NoError(t, err)
		ks := new(AMEVKeyStore)
		require.NoError(t, ks.FromBytes(ksBytes))
		kss[i] = ks
		fmt.Printf("%s:\n\t%s\n", addrsPrivnet[i].addr, hex.EncodeToString(ksBytes))
		os.Remove(fmt.Sprintf("../../privnet/seven/node%d/kss.txt", addrsPrivnet[i].i))
		os.WriteFile(fmt.Sprintf("../../privnet/seven/node%d/amev_keystore.txt", addrsPrivnet[i].i), []byte(hex.EncodeToString(ksBytes)), os.ModePerm)
	}

	// Encrypt
	msg := []byte("pizza pizza pizza pizza pizza pizza pizza pizza pizza pizza pizza pizza pizza")
	encryptedKey, encryptedMsg, err := kss[0].Encrypt(msg)
	if err != nil {
		t.Fatalf(err.Error())
	}

	fmt.Printf("encryptedKey: %s\nencryptedMsg: %s\n", hex.EncodeToString(encryptedKey.ToBytes()), hex.EncodeToString(encryptedMsg))
	// Verify ciphertext
	if err := encryptedKey.Verify(); err != nil {
		t.Fatalf("invalid ciphertext.")
	}

	// Generate shares
	shares := make(map[int][]*tpke.DecryptionShare)
	for i := 0; i < size-2; i++ {
		share, err := kss[i].DecryptWithShare([]*tpke.CipherText{encryptedKey})
		if err != nil {
			t.Fatalf(err.Error())
		}
		shares[i+1] = share
	}

	// Decrypt
	results, err := kss[0].AggregateAndDecryptWithShare([]*tpke.CipherText{encryptedKey}, [][]byte{encryptedMsg}, shares)
	if err != nil {
		t.Fatalf(err.Error())
	}
	for i := 0; i < len(msg); i++ {
		if msg[i] != results[0][i] {
			t.Fatalf("decryption failed.")
		}
	}
}

